// C2 - ((C1 -nuw X) & M) --> X & (M & bound)
// where M clears low bits: ~M + 1 is a power of 2,
// C1 has all those low bits set, and C2 == C1 & M.
const APInt *C1Val, *Mask;
Value *SubOp;
if (match(Op1, m_c_And(m_Value(SubOp), m_APInt(Mask)))) {
  if (match(SubOp, m_OneUse(m_Sub(m_APInt(C1Val), m_Value(X)))) &&
      cast<BinaryOperator>(SubOp)->hasNoUnsignedWrap()) {
    APInt C2Val = C->getUniqueInteger();
    APInt NotM = ~(*Mask);
    APInt NotMPlus1 = NotM + 1;
    if (NotMPlus1.isPowerOf2()) {
      // Low bits of C1 must be all 1s: C1 & ~M == ~M.
      if ((*C1Val & NotM) == NotM) {
        // C2 must equal C1 with low bits cleared: C2 == C1 & M.
        if ((*C1Val & *Mask) == C2Val) {
          Type *Ty = I.getType();
          unsigned BitWidth = Ty->getScalarSizeInBits();
          APInt Bound =
              APInt::getLowBitsSet(BitWidth, C1Val->getActiveBits());
          APInt ResultMask = *Mask & Bound;
          return BinaryOperator::CreateAnd(
              X, ConstantInt::get(Ty, ResultMask));
        }
      }
    }
  }
}
